{
  "description": "Integrated Driver Drowsiness and Rear Vehicle Monitoring System",
  "requestFramePermissions": [
    "camera"
  ],
  "name": "SafetyVision Pro"
}

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';

// ==========================================
// TYPES & DECLARATIONS
// ==========================================
declare global {
  interface Window {
    FaceMesh: any;
    cocoSsd: any;
  }
}

// Configuration Constants
const CONFIG = {
  EYE_THRESHOLD: 0.20,
  BLINK_FRAMES: 5,       // Reduced for web responsiveness
  DROWSY_FRAMES: 15,
  SAFE_DISTANCE: 8.0,    // Meters
  KNOWN_WIDTH: 2.5,      // Meters (Avg Truck Width)
  FOCAL_LENGTH: 600,     // Adjusted for typical webcam FOV (approx)
  HEAVY_VEHICLES: ['bus', 'truck']
};

// ==========================================
// HELPER CLASSES / FUNCTIONS
// ==========================================

// Sound Generator using Web Audio API
class SoundSystem {
  ctx: AudioContext | null = null;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    } catch (e) {
      console.error("Web Audio API not supported");
    }
  }

  playBeep(frequency = 1000, type: OscillatorType = 'square') {
    if (!this.ctx) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    osc.type = type;
    osc.frequency.value = frequency;
    gain.gain.value = 0.1;

    osc.start();
    setTimeout(() => osc.stop(), 200);
  }
}

const audioSystem = new SoundSystem();

// Distance Estimation
function estimateDistance(pixelWidth: number): number | null {
  if (pixelWidth <= 0) return null;
  return (CONFIG.KNOWN_WIDTH * CONFIG.FOCAL_LENGTH) / pixelWidth;
}

// EAR Calculation
function getEAR(landmarks: any, indices: number[], width: number, height: number) {
  const getPoint = (idx: number) => ({ x: landmarks[idx].x * width, y: landmarks[idx].y * height });

  // Euclidean distance
  const dist = (p1: any, p2: any) => Math.sqrt(Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2));

  // Indices: [left, top1, top2, right, bot1, bot2] -> based on provided Python logic
  // Python: P1, P2, P3, P4, P5, P6 corresponds to MediaPipe mesh points
  // 33, 160, 158, 133, 153, 144 for Left
  const p1 = getPoint(indices[0]);
  const p2 = getPoint(indices[1]);
  const p3 = getPoint(indices[2]);
  const p4 = getPoint(indices[3]);
  const p5 = getPoint(indices[4]);
  const p6 = getPoint(indices[5]);

  const A = dist(p2, p6);
  const B = dist(p3, p5);
  const C = dist(p1, p4);

  return (A + B) / (2.0 * C);
}

// ==========================================
// MAIN COMPONENT
// ==========================================

const App = () => {
  // -- State --
  const [driverDeviceId, setDriverDeviceId] = useState<string>('');
  const [rearDeviceId, setRearDeviceId] = useState<string>('');
  const [devices, setDevices] = useState<MediaDeviceInfo[]>([]);

  const [driverStatus, setDriverStatus] = useState<'AWAKE' | 'DROWSY'>('AWAKE');
  const [earValue, setEarValue] = useState<number>(0);

  const [detectedVehicle, setDetectedVehicle] = useState<{label: string, distance: number} | null>(null);
  const [collisionWarning, setCollisionWarning] = useState<boolean>(false);

  const [modelsLoaded, setModelsLoaded] = useState(false);

  // -- Refs --
  const driverVideoRef = useRef<HTMLVideoElement>(null);
  const rearVideoRef = useRef<HTMLVideoElement>(null);
  const driverCanvasRef = useRef<HTMLCanvasElement>(null);
  const rearCanvasRef = useRef<HTMLCanvasElement>(null);

  // -- Logic Refs (Mutable values for loops) --
  const faceMeshRef = useRef<any>(null);
  const objectDetectorRef = useRef<any>(null);
  const earCounterRef = useRef(0);
  const lastAlertTimeRef = useRef(0);

  // 1. Initialize Models
  useEffect(() => {
    const loadModels = async () => {
      console.log("Loading models...");

      // Load Face Mesh
      const faceMesh = new window.FaceMesh({
        locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/face_mesh/${file}`,
      });
      faceMesh.setOptions({
        maxNumFaces: 1,
        refineLandmarks: true,
        minDetectionConfidence: 0.5,
        minTrackingConfidence: 0.5,
      });
      faceMesh.onResults(onFaceResults);
      faceMeshRef.current = faceMesh;

      // Load Coco SSD (Lightweight YOLO alternative for Web)
      const detector = await window.cocoSsd.load();
      objectDetectorRef.current = detector;

      setModelsLoaded(true);
      console.log("Models loaded!");
    };

    loadModels();

    // Get Cameras
    navigator.mediaDevices.enumerateDevices().then(devs => {
      const videoDevs = devs.filter(d => d.kind === 'videoinput');
      setDevices(videoDevs);
      if (videoDevs.length > 0) setDriverDeviceId(videoDevs[0].deviceId);
      // If a second camera exists, use it for rear. Otherwise duplicate for demo.
      if (videoDevs.length > 1) {
        setRearDeviceId(videoDevs[1].deviceId);
      } else if (videoDevs.length > 0) {
        setRearDeviceId(videoDevs[0].deviceId);
      }
    });

  }, []);

  // 2. Start Camera Streams
  useEffect(() => {
    startStream(driverVideoRef.current, driverDeviceId);
  }, [driverDeviceId]);

  useEffect(() => {
    startStream(rearVideoRef.current, rearDeviceId);
  }, [rearDeviceId]);

  const startStream = (videoEl: HTMLVideoElement | null, deviceId: string) => {
    if (!videoEl || !deviceId) return;
    navigator.mediaDevices.getUserMedia({
      video: { deviceId: { exact: deviceId }, width: 640, height: 480 }
    }).then(stream => {
      videoEl.srcObject = stream;
      videoEl.play();
    }).catch(err => console.error("Camera error:", err));
  };

  // 3. Processing Loops
  useEffect(() => {
    if (!modelsLoaded) return;

    const interval = setInterval(() => {
      processRearFrame();
    }, 100); // 10 FPS for object detection is sufficient

    const animFrame = requestAnimationFrame(processDriverFrameLoop);

    return () => {
      clearInterval(interval);
      cancelAnimationFrame(animFrame);
    };
  }, [modelsLoaded, driverDeviceId, rearDeviceId]);


  // -- Driver Processing (Face Mesh) --
  const processDriverFrameLoop = async () => {
    if (driverVideoRef.current && faceMeshRef.current) {
      if (driverVideoRef.current.readyState === 4) {
        await faceMeshRef.current.send({ image: driverVideoRef.current });
      }
    }
    requestAnimationFrame(processDriverFrameLoop);
  };

  const onFaceResults = (results: any) => {
    const canvas = driverCanvasRef.current;
    const video = driverVideoRef.current;
    if (!canvas || !video || !results.multiFaceLandmarks || results.multiFaceLandmarks.length === 0) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = video.videoWidth;
    const height = video.videoHeight;
    canvas.width = width;
    canvas.height = height;
    ctx.clearRect(0, 0, width, height);

    const landmarks = results.multiFaceLandmarks[0];

    // Indices based on Python code provided
    const LEFT_EYE = [33, 160, 158, 133, 153, 144];
    const RIGHT_EYE = [362, 385, 387, 263, 373, 380];

    const leftEAR = getEAR(landmarks, LEFT_EYE, width, height);
    const rightEAR = getEAR(landmarks, RIGHT_EYE, width, height);
    const avgEAR = (leftEAR + rightEAR) / 2.0;

    setEarValue(avgEAR);

    // Logic
    if (avgEAR < CONFIG.EYE_THRESHOLD) {
      earCounterRef.current += 1;
    } else {
      if (earCounterRef.current >= CONFIG.BLINK_FRAMES) {
        // Blink logic could go here
      }
      earCounterRef.current = 0;
    }

    if (earCounterRef.current >= CONFIG.DROWSY_FRAMES) {
      setDriverStatus('DROWSY');
      triggerAlarm('low');
    } else {
      setDriverStatus('AWAKE');
    }

    // Draw Eyes
    ctx.strokeStyle = avgEAR < CONFIG.EYE_THRESHOLD ? 'red' : '#00ff00';
    ctx.lineWidth = 2;
    // Helper to draw eye path
    const drawEye = (indices: number[]) => {
      ctx.beginPath();
      indices.forEach((idx, i) => {
        const x = landmarks[idx].x * width;
        const y = landmarks[idx].y * height;
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.closePath();
      ctx.stroke();
    };
    drawEye(LEFT_EYE);
    drawEye(RIGHT_EYE);
  };

  // -- Rear Processing (Object Detection) --
  const processRearFrame = async () => {
    const video = rearVideoRef.current;
    const canvas = rearCanvasRef.current;
    const detector = objectDetectorRef.current;

    if (!video || !canvas || !detector || video.readyState !== 4) return;

    // Detect
    const predictions = await detector.detect(video);

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    let foundHeavyVehicle = false;
    let closestDist = Infinity;
    let label = "";

    predictions.forEach((pred: any) => {
      // Filter for Bus or Truck
      if (CONFIG.HEAVY_VEHICLES.includes(pred.class)) {
        const [x, y, w, h] = pred.bbox;
        const dist = estimateDistance(w);

        if (dist !== null) {
          foundHeavyVehicle = true;

          // Draw Box
          const isDanger = dist < CONFIG.SAFE_DISTANCE;
          ctx.strokeStyle = isDanger ? 'red' : '#00ff00';
          ctx.lineWidth = 3;
          ctx.strokeRect(x, y, w, h);

          // Draw Label
          ctx.fillStyle = isDanger ? 'red' : '#00ff00';
          ctx.font = '18px Arial';
          ctx.fillText(`${pred.class.toUpperCase()} ${dist.toFixed(1)}m`, x, y - 10);

          if (dist < closestDist) {
            closestDist = dist;
            label = pred.class;
          }
        }
      }
    });

    if (foundHeavyVehicle) {
      setDetectedVehicle({ label, distance: closestDist });
      if (closestDist < CONFIG.SAFE_DISTANCE) {
        setCollisionWarning(true);
        triggerAlarm('high');
      } else {
        setCollisionWarning(false);
      }
    } else {
      setDetectedVehicle(null);
      setCollisionWarning(false);
    }
  };

  const triggerAlarm = (urgency: 'low' | 'high') => {
    const now = Date.now();
    // Prevent overlapping sound spam
    if (now - lastAlertTimeRef.current > 1000) {
      if (urgency === 'high') audioSystem.playBeep(1500, 'sawtooth');
      else audioSystem.playBeep(800, 'square');
      lastAlertTimeRef.current = now;
    }
  };

  // ==========================================
  // RENDER
  // ==========================================
  return (
    <div className="min-h-screen p-4 flex flex-col gap-4 font-sans">
      <header className="flex justify-between items-center bg-gray-800 p-4 rounded-lg shadow-lg">
        <div>
          <h1 className="text-2xl font-bold text-blue-400">SafetyVision Pro</h1>
          <p className="text-gray-400 text-sm">Integrated Drowsiness & Rear Vehicle Monitor</p>
        </div>
        <div className="flex gap-4 items-center">
          <div className={`px-4 py-2 rounded font-bold ${driverStatus === 'DROWSY' ? 'bg-red-600 animate-pulse' : 'bg-green-600'}`}>
            DRIVER: {driverStatus}
          </div>
          <div className={`px-4 py-2 rounded font-bold ${collisionWarning ? 'bg-red-600 animate-pulse' : 'bg-gray-700'}`}>
            REAR: {collisionWarning ? 'COLLISION WARNING' : 'SAFE'}
          </div>
        </div>
      </header>

      {!modelsLoaded && (
        <div className="flex-1 flex items-center justify-center text-xl text-yellow-400 animate-pulse">
          Loading AI Models... Please wait...
        </div>
      )}

      <main className={`grid grid-cols-1 md:grid-cols-2 gap-4 flex-1 ${!modelsLoaded ? 'hidden' : ''}`}>

        {/* DRIVER PANEL */}
        <div className="flex flex-col gap-2">
          <div className="flex justify-between items-center bg-gray-800 p-2 rounded">
            <h2 className="font-semibold text-lg">Driver Monitor (EAR: {earValue.toFixed(2)})</h2>
            <select 
              className="bg-gray-700 text-sm p-1 rounded"
              value={driverDeviceId}
              onChange={(e) => setDriverDeviceId(e.target.value)}
            >
              {devices.map(d => <option key={d.deviceId} value={d.deviceId}>{d.label || `Camera ${d.deviceId.slice(0,5)}`}</option>)}
            </select>
          </div>
          <div className={`video-container aspect-video relative border-4 ${driverStatus === 'DROWSY' ? 'border-red-600 alert-overlay' : 'border-gray-700'}`}>
            <video ref={driverVideoRef} autoPlay playsInline muted className="transform scale-x-[-1]" />
            <canvas ref={driverCanvasRef} className="transform scale-x-[-1]" />
            <div className="absolute top-2 left-2 bg-black/50 px-2 rounded text-xs text-white">
              Target: Eyes
            </div>
          </div>
        </div>

        {/* REAR PANEL */}
        <div className="flex flex-col gap-2">
           <div className="flex justify-between items-center bg-gray-800 p-2 rounded">
            <h2 className="font-semibold text-lg">Rear Traffic Monitor</h2>
            <select 
              className="bg-gray-700 text-sm p-1 rounded"
              value={rearDeviceId}
              onChange={(e) => setRearDeviceId(e.target.value)}
            >
              {devices.map(d => <option key={d.deviceId} value={d.deviceId}>{d.label || `Camera ${d.deviceId.slice(0,5)}`}</option>)}
            </select>
          </div>
          <div className={`video-container aspect-video relative border-4 ${collisionWarning ? 'border-red-600 alert-overlay' : 'border-gray-700'}`}>
            <video ref={rearVideoRef} autoPlay playsInline muted />
            <canvas ref={rearCanvasRef} />

            {detectedVehicle ? (
               <div className="absolute bottom-4 left-4 right-4 bg-black/70 p-2 rounded flex justify-between items-center">
                 <span className="font-bold text-lg text-white uppercase">{detectedVehicle.label}</span>
                 <span className={`text-xl font-mono font-bold ${collisionWarning ? 'text-red-500' : 'text-green-400'}`}>
                   {detectedVehicle.distance.toFixed(2)}m
                 </span>
               </div>
            ) : (
              <div className="absolute top-2 left-2 bg-black/50 px-2 rounded text-xs text-gray-400">
                Scanning for Heavy Vehicles...
              </div>
            )}
          </div>
        </div>

      </main>

      <footer className="text-center text-xs text-gray-500 mt-4">
        System uses TensorFlow.js (Coco-SSD) & MediaPipe FaceMesh. Processed locally in browser.
      </footer>
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { createRoot } from 'react-dom/client';

// ==========================================
// 1. GLOBAL TYPES & CONFIGURATION
// ==========================================
declare global {
  interface Window {
    FaceMesh: any;
    cocoSsd: any;
    tf: any;
  }
}

const CONFIG = {
  // Drowsiness Thresholds
  EAR_THRESHOLD: 0.20,
  MAR_THRESHOLD: 0.50,    // Mouth Aspect Ratio for Yawning
  BLINK_FRAMES: 5,
  DROWSY_FRAMES: 15,
  PERCLOS_WINDOW: 60000,  // 60 seconds

  // Traffic Thresholds
  SAFE_DISTANCE: 8.0,     // Meters
  KNOWN_WIDTH: 2.5,       // Avg Truck Width (Meters)
  DEFAULT_FOCAL: 600,     // Default Focal Length
  HEAVY_VEHICLES: ['bus', 'truck'],

  // System
  TRAFFIC_INTERVAL_MS: 100, // Traffic detection runs at ~10 FPS
  LOG_LIMIT: 1000,
};

// ==========================================
// 2. MODULAR ENGINES & UTILS
// ==========================================

// --- Logger System ---
interface LogEntry {
  timestamp: string;
  type: 'INFO' | 'WARNING' | 'CRITICAL';
  message: string;
  data?: string;
}

class SystemLogger {
  private logs: LogEntry[] = [];

  log(type: 'INFO' | 'WARNING' | 'CRITICAL', message: string, data?: string) {
    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      type,
      message,
      data: data || ''
    };
    this.logs.unshift(entry); // Add to start
    if (this.logs.length > CONFIG.LOG_LIMIT) this.logs.pop();
  }

  getLogs() { return this.logs; }

  downloadCSV() {
    const headers = ['Timestamp', 'Type', 'Message', 'Data'];
    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...this.logs.map(e => `${e.timestamp},${e.type},"${e.message}","${e.data}"`)].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `safety_vision_logs_${Date.now()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
}

const logger = new SystemLogger();

// --- Sound & Voice System ---
class AlertSystem {
  private audioCtx: AudioContext | null = null;
  private lastSpeechTime = 0;

  constructor() {
    try {
      this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    } catch (e) { console.error("WebAudio API missing"); }
  }

  beep(frequency = 1000, duration = 200, type: OscillatorType = 'square') {
    if (!this.audioCtx) return;
    const osc = this.audioCtx.createOscillator();
    const gain = this.audioCtx.createGain();
    osc.connect(gain);
    gain.connect(this.audioCtx.destination);
    osc.type = type;
    osc.frequency.value = frequency;
    gain.gain.value = 0.1;
    osc.start();
    setTimeout(() => osc.stop(), duration);
  }

  speak(text: string) {
    const now = Date.now();
    if (now - this.lastSpeechTime < 3000) return; // Debounce voice

    if ('speechSynthesis' in window) {
      if (window.speechSynthesis.speaking) return;
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.rate = 1.2;
      window.speechSynthesis.speak(utterance);
      this.lastSpeechTime = now;
    }
  }
}

const alertSystem = new AlertSystem();

// --- Math Utils ---
const euclidean = (p1: any, p2: any) => Math.sqrt(Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2));

// --- Drowsiness Engine ---
class DrowsinessEngine {
  private eyeHistory: {timestamp: number, closed: boolean}[] = [];

  // Landmarks
  // Left Eye: 33, 160, 158, 133, 153, 144
  // Right Eye: 362, 385, 387, 263, 373, 380
  // Mouth: 13, 14 (Upper/Lower inner), 78, 308 (Left/Right corners)

  calculateEAR(landmarks: any[]) {
    const getP = (i: number) => landmarks[i];

    const ear = (indices: number[]) => {
      const v1 = euclidean(getP(indices[1]), getP(indices[5]));
      const v2 = euclidean(getP(indices[2]), getP(indices[4]));
      const h = euclidean(getP(indices[0]), getP(indices[3]));
      return (v1 + v2) / (2.0 * h);
    }

    const left = ear([33, 160, 158, 133, 153, 144]);
    const right = ear([362, 385, 387, 263, 373, 380]);
    return (left + right) / 2.0;
  }

  calculateMAR(landmarks: any[]) {
    // Vertical: 13 to 14
    const v = euclidean(landmarks[13], landmarks[14]);
    // Horizontal: 78 to 308
    const h = euclidean(landmarks[78], landmarks[308]);
    return v / h;
  }

  calculatePERCLOS() {
    const now = Date.now();
    // Clean old history
    this.eyeHistory = this.eyeHistory.filter(e => now - e.timestamp < CONFIG.PERCLOS_WINDOW);
    if (this.eyeHistory.length === 0) return 0;

    const closedCount = this.eyeHistory.filter(e => e.closed).length;
    return closedCount / this.eyeHistory.length;
  }

  updateHistory(isClosed: boolean) {
    this.eyeHistory.push({ timestamp: Date.now(), closed: isClosed });
  }
}

// --- Traffic Engine ---
class TrafficEngine {
  private history: number[] = [];

  estimateDistance(pixelWidth: number, focalLength: number) {
    if (pixelWidth <= 0) return null;
    return (CONFIG.KNOWN_WIDTH * focalLength) / pixelWidth;
  }

  // Exponential Moving Average for smoothing
  smoothDistance(newDist: number) {
    this.history.push(newDist);
    if (this.history.length > 5) this.history.shift();
    return this.history.reduce((a, b) => a + b, 0) / this.history.length;
  }
}

const drowsyEngine = new DrowsinessEngine();
const trafficEngine = new TrafficEngine();

// ==========================================
// 3. MAIN COMPONENT
// ==========================================
const App = () => {
  // -- Setup State --
  const [driverDeviceId, setDriverDeviceId] = useState<string>('');
  const [rearDeviceId, setRearDeviceId] = useState<string>('');
  const [devices, setDevices] = useState<MediaDeviceInfo[]>([]);
  const [modelsLoaded, setModelsLoaded] = useState(false);

  // -- Metrics State --
  const [fps, setFps] = useState(0);
  const [ear, setEar] = useState(0);
  const [mar, setMar] = useState(0);
  const [perclos, setPerclos] = useState(0);
  const [focalLength, setFocalLength] = useState(CONFIG.DEFAULT_FOCAL);

  // -- Alerts State --
  const [driverStatus, setDriverStatus] = useState<'AWAKE' | 'DROWSY' | 'YAWNING'>('AWAKE');
  const [rearStatus, setRearStatus] = useState<'SAFE' | 'WARNING' | 'CRITICAL'>('SAFE');
  const [detectedObj, setDetectedObj] = useState<{label: string, dist: number} | null>(null);

  // -- Refs --
  const driverVideo = useRef<HTMLVideoElement>(null);
  const rearVideo = useRef<HTMLVideoElement>(null);
  const driverCanvas = useRef<HTMLCanvasElement>(null);
  const rearCanvas = useRef<HTMLCanvasElement>(null);

  // Mutable Refs for loops
  const faceMeshRef = useRef<any>(null);
  const cocoRef = useRef<any>(null);
  const earCounter = useRef(0);
  const frameCount = useRef(0);
  const lastTime = useRef(performance.now());
  const lastTrafficProcess = useRef(0);

  // 1. Initialization
  useEffect(() => {
    const init = async () => {
      try {
        // GPU Acceleration
        if (window.tf) {
          await window.tf.setBackend('webgl');
          console.log("TF Backend:", window.tf.getBackend());
        }

        // Load Models
        const faceMesh = new window.FaceMesh({
          locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/face_mesh/${file}`,
        });
        faceMesh.setOptions({
          maxNumFaces: 1,
          refineLandmarks: true,
          minDetectionConfidence: 0.5,
          minTrackingConfidence: 0.5,
        });
        faceMesh.onResults(onFaceResults);
        faceMeshRef.current = faceMesh;

        const net = await window.cocoSsd.load();
        cocoRef.current = net;

        // Load Cameras
        const devs = await navigator.mediaDevices.enumerateDevices();
        const videos = devs.filter(d => d.kind === 'videoinput');
        setDevices(videos);
        if (videos.length > 0) setDriverDeviceId(videos[0].deviceId);
        if (videos.length > 1) setRearDeviceId(videos[1].deviceId);
        else if (videos.length > 0) setRearDeviceId(videos[0].deviceId);

        setModelsLoaded(true);
        logger.log('INFO', 'System initialized successfully');
      } catch (e) {
        console.error(e);
        logger.log('CRITICAL', 'Failed to initialize AI models');
      }
    };
    init();
  }, []);

  // 2. Camera Stream Handlers
  useEffect(() => {
    if (driverVideo.current && driverDeviceId) {
      navigator.mediaDevices.getUserMedia({ video: { deviceId: { exact: driverDeviceId }, width: 640, height: 480 } })
        .then(s => { if(driverVideo.current) driverVideo.current.srcObject = s; });
    }
  }, [driverDeviceId]);

  useEffect(() => {
    if (rearVideo.current && rearDeviceId) {
      navigator.mediaDevices.getUserMedia({ video: { deviceId: { exact: rearDeviceId }, width: 640, height: 480 } })
        .then(s => { if(rearVideo.current) rearVideo.current.srcObject = s; });
    }
  }, [rearDeviceId]);

  // 3. Main Loop
  useEffect(() => {
    if (!modelsLoaded) return;
    let animId: number;

    const loop = async () => {
      const now = performance.now();

      // Calculate FPS
      frameCount.current++;
      if (now - lastTime.current >= 1000) {
        setFps(frameCount.current);
        frameCount.current = 0;
        lastTime.current = now;
      }

      // 1. Process Driver (High Priority - Every Frame)
      if (driverVideo.current && driverVideo.current.readyState === 4) {
        await faceMeshRef.current.send({ image: driverVideo.current });
      }

      // 2. Process Traffic (Throttled - Every 100ms)
      if (now - lastTrafficProcess.current > CONFIG.TRAFFIC_INTERVAL_MS) {
        await processTraffic();
        lastTrafficProcess.current = now;
      }

      animId = requestAnimationFrame(loop);
    };

    animId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animId);
  }, [modelsLoaded, focalLength]); // Re-bind if focal length changes

  // --- Logic: Drowsiness ---
  const onFaceResults = (results: any) => {
    if (!results.multiFaceLandmarks || results.multiFaceLandmarks.length === 0) return;

    const landmarks = results.multiFaceLandmarks[0];
    const width = 640;
    const height = 480;

    // Calc Metrics
    const currentEar = drowsyEngine.calculateEAR(landmarks);
    const currentMar = drowsyEngine.calculateMAR(landmarks);
    const isClosed = currentEar < CONFIG.EAR_THRESHOLD;

    drowsyEngine.updateHistory(isClosed);
    const currentPerclos = drowsyEngine.calculatePERCLOS();

    setEar(currentEar);
    setMar(currentMar);
    setPerclos(currentPerclos);

    // State Machine
    let status: 'AWAKE' | 'DROWSY' | 'YAWNING' = 'AWAKE';

    // Yawn Check
    if (currentMar > CONFIG.MAR_THRESHOLD) {
      status = 'YAWNING';
      logger.log('WARNING', 'Driver Yawning Detected', `MAR: ${currentMar.toFixed(2)}`);
    }

    // Drowsy Check
    if (isClosed) {
      earCounter.current++;
    } else {
      // Recovery logic
      if (earCounter.current > 0) earCounter.current--; 
    }

    if (earCounter.current > CONFIG.DROWSY_FRAMES || currentPerclos > 0.4) { // >40% closed in last minute
      status = 'DROWSY';
      logger.log('CRITICAL', 'Driver Drowsiness Detected', `PERCLOS: ${(currentPerclos*100).toFixed(1)}%`);
      alertSystem.beep(1000, 500, 'sawtooth');
      alertSystem.speak("Wake up! You are drowsy.");
    }

    setDriverStatus(status);
    drawDriverOverlay(landmarks, width, height, status);
  };

  const drawDriverOverlay = (landmarks: any[], w: number, h: number, status: string) => {
    const canvas = driverCanvas.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = w; 
    canvas.height = h;
    ctx.clearRect(0,0,w,h);

    const color = status === 'AWAKE' ? '#00ff00' : (status === 'YAWNING' ? '#ffff00' : '#ff0000');

    // Draw Eyes
    ctx.strokeStyle = color;
    ctx.lineWidth = 2;
    [ [33, 160, 158, 133, 153, 144], [362, 385, 387, 263, 373, 380] ].forEach(eye => {
      ctx.beginPath();
      eye.forEach((idx, i) => {
        const x = landmarks[idx].x * w;
        const y = landmarks[idx].y * h;
        if (i===0) ctx.moveTo(x,y); else ctx.lineTo(x,y);
      });
      ctx.closePath();
      ctx.stroke();
    });

    // Draw Mouth if Yawning
    if (status === 'YAWNING') {
      const x = landmarks[13].x * w;
      const y = landmarks[13].y * h;
      ctx.strokeRect(x - 20, y - 20, 40, 40);
      ctx.fillStyle = color;
      ctx.fillText("YAWN", x, y - 30);
    }
  };

  // --- Logic: Traffic ---
  const processTraffic = async () => {
    if (!rearVideo.current || !cocoRef.current || rearVideo.current.readyState !== 4) return;

    const predictions = await cocoRef.current.detect(rearVideo.current);
    const canvas = rearCanvas.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = rearVideo.current.videoWidth;
    canvas.height = rearVideo.current.videoHeight;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    let closest: {label: string, dist: number} | null = null;
    let minDiff = Infinity;

    predictions.forEach((pred: any) => {
      if (CONFIG.HEAVY_VEHICLES.includes(pred.class)) {
        const [x, y, w, h] = pred.bbox;
        const rawDist = trafficEngine.estimateDistance(w, focalLength);

        if (rawDist !== null) {
          const smoothDist = trafficEngine.smoothDistance(rawDist);

          const isCritical = smoothDist < CONFIG.SAFE_DISTANCE;
          const color = isCritical ? '#ff0000' : '#00ff00';

          // Draw Box
          ctx.strokeStyle = color;
          ctx.lineWidth = 3;
          ctx.strokeRect(x, y, w, h);

          // Draw Label
          ctx.fillStyle = color;
          ctx.font = 'bold 16px Arial';
          ctx.fillText(`${pred.class.toUpperCase()} ${smoothDist.toFixed(1)}m`, x, y - 10);

          if (smoothDist < minDiff) {
            minDiff = smoothDist;
            closest = { label: pred.class, dist: smoothDist };
          }
        }
      }
    });

    setDetectedObj(closest);

    if (closest && closest.dist < CONFIG.SAFE_DISTANCE) {
      setRearStatus('CRITICAL');
      logger.log('CRITICAL', 'Collision Warning', `Dist: ${closest.dist.toFixed(2)}m`);
      alertSystem.beep(1500, 300, 'square');
      alertSystem.speak("Warning. Vehicle too close.");
    } else if (closest) {
      setRearStatus('WARNING');
    } else {
      setRearStatus('SAFE');
    }
  };

  // 4. Render
  return (
    <div className="min-h-screen bg-gray-900 text-white font-sans flex flex-col">
      {/* HEADER */}
      <header className="bg-gray-800 p-4 shadow-lg flex justify-between items-center z-10">
        <div>
          <h1 className="text-2xl font-bold text-blue-400 tracking-wider">SafetyVision <span className="text-white">Pro</span></h1>
          <div className="text-xs text-gray-400 flex gap-4 mt-1">
            <span>FPS: <span className="text-green-400 font-mono">{fps}</span></span>
            <span>GPU: <span className="text-green-400 font-mono">{modelsLoaded ? 'ON' : 'OFF'}</span></span>
          </div>
        </div>

        <div className="flex gap-4">
          <div className={`px-6 py-2 rounded-lg font-bold transition-colors duration-200 border-2 
            ${driverStatus === 'AWAKE' ? 'bg-green-900/50 border-green-500 text-green-400' : 
              driverStatus === 'YAWNING' ? 'bg-yellow-900/50 border-yellow-500 text-yellow-400' : 
              'bg-red-900/50 border-red-500 text-red-500 animate-pulse'}`}>
             DRIVER: {driverStatus}
          </div>
          <div className={`px-6 py-2 rounded-lg font-bold transition-colors duration-200 border-2
            ${rearStatus === 'SAFE' ? 'bg-gray-800 border-gray-600 text-gray-400' : 
              rearStatus === 'CRITICAL' ? 'bg-red-900/50 border-red-500 text-red-500 animate-pulse' : 
              'bg-blue-900/50 border-blue-500 text-blue-400'}`}>
             REAR: {rearStatus === 'CRITICAL' ? 'COLLISION WARNING' : (detectedObj ? `${detectedObj.dist.toFixed(1)}m` : 'CLEAR')}
          </div>
        </div>
      </header>

      {/* MAIN CONTENT */}
      {!modelsLoaded ? (
        <div className="flex-1 flex flex-col items-center justify-center gap-4">
          <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-xl animate-pulse">Initializing AI Models & GPU...</p>
        </div>
      ) : (
        <main className="flex-1 p-4 grid grid-cols-1 lg:grid-cols-2 gap-6 overflow-y-auto">

          {/* DRIVER PANEL */}
          <div className="flex flex-col gap-2">
             <div className="flex justify-between items-end pb-2 border-b border-gray-700">
                <h2 className="text-lg font-semibold flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-blue-400"></span> Driver Monitor
                </h2>
                <select className="bg-gray-800 text-xs p-1 rounded border border-gray-600 outline-none"
                  value={driverDeviceId} onChange={e => setDriverDeviceId(e.target.value)}>
                  {devices.map(d => <option key={d.deviceId} value={d.deviceId}>{d.label || d.deviceId.slice(0,8)}</option>)}
                </select>
             </div>

             <div className="relative bg-black rounded-lg overflow-hidden shadow-2xl aspect-video border border-gray-700">
               <video ref={driverVideo} autoPlay playsInline muted className="w-full h-full object-cover transform scale-x-[-1]" />
               <canvas ref={driverCanvas} className="absolute top-0 left-0 w-full h-full transform scale-x-[-1]" />

               {/* Metrics Overlay */}
               <div className="absolute top-2 left-2 bg-black/60 backdrop-blur-sm p-2 rounded text-xs font-mono space-y-1 border border-white/10">
                 <div className="flex justify-between w-32"><span>EAR:</span> <span className={ear < CONFIG.EAR_THRESHOLD ? 'text-red-400' : 'text-green-400'}>{ear.toFixed(2)}</span></div>
                 <div className="flex justify-between w-32"><span>MAR:</span> <span className={mar > CONFIG.MAR_THRESHOLD ? 'text-yellow-400' : 'text-green-400'}>{mar.toFixed(2)}</span></div>
                 <div className="flex justify-between w-32"><span>PERCLOS:</span> <span className={perclos > 0.4 ? 'text-red-400' : 'text-green-400'}>{(perclos*100).toFixed(0)}%</span></div>
               </div>
             </div>
          </div>

          {/* REAR PANEL */}
          <div className="flex flex-col gap-2">
             <div className="flex justify-between items-end pb-2 border-b border-gray-700">
                <h2 className="text-lg font-semibold flex items-center gap-2">
                   <span className="w-2 h-2 rounded-full bg-orange-400"></span> Rear Monitor
                </h2>
                <select className="bg-gray-800 text-xs p-1 rounded border border-gray-600 outline-none"
                  value={rearDeviceId} onChange={e => setRearDeviceId(e.target.value)}>
                  {devices.map(d => <option key={d.deviceId} value={d.deviceId}>{d.label || d.deviceId.slice(0,8)}</option>)}
                </select>
             </div>

             <div className="relative bg-black rounded-lg overflow-hidden shadow-2xl aspect-video border border-gray-700">
               <video ref={rearVideo} autoPlay playsInline muted className="w-full h-full object-cover" />
               <canvas ref={rearCanvas} className="absolute top-0 left-0 w-full h-full" />

               {/* Distance Info */}
               {detectedObj && (
                 <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-black/80 backdrop-blur px-4 py-2 rounded-full border border-red-500/50">
                    <span className="text-xl font-bold">{detectedObj.label.toUpperCase()}</span>
                    <span className="mx-2 text-gray-500">|</span>
                    <span className={`text-2xl font-mono ${detectedObj.dist < CONFIG.SAFE_DISTANCE ? 'text-red-500 animate-pulse' : 'text-green-400'}`}>
                      {detectedObj.dist.toFixed(1)}m
                    </span>
                 </div>
               )}
             </div>

             {/* Calibration Controls */}
             <div className="bg-gray-800 p-3 rounded text-xs flex items-center gap-4 border border-gray-700">
               <span className="font-bold text-gray-400">CALIBRATION</span>
               <div className="flex-1 flex flex-col">
                 <div className="flex justify-between mb-1">
                   <span>Focal Length</span>
                   <span className="font-mono text-blue-400">{focalLength}px</span>
                 </div>
                 <input type="range" min="400" max="1500" step="10" 
                    value={focalLength} 
                    onChange={(e) => setFocalLength(Number(e.target.value))} 
                    className="w-full h-1 bg-gray-600 rounded-lg appearance-none cursor-pointer" 
                 />
               </div>
             </div>
          </div>

        </main>
      )}

      {/* FOOTER / LOGS */}
      <footer className="bg-gray-800 p-2 text-xs flex justify-between items-center border-t border-gray-700">
        <div className="flex gap-4">
          <button onClick={() => logger.downloadCSV()} className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded transition">
            Download Logs (CSV)
          </button>
